// Function to handle sending a message
function sendMessage() {
  var messageInput = document.getElementById("message-input");
  var messageContainer = document.getElementById("message-container");

  // Create a new message element
  var message = document.createElement("div");
  message.classList.add("message");

  // Check for tagged users
  var taggedUsers = messageInput.value.match(/@(\w+)/g);
  if (taggedUsers) {
    taggedUsers.forEach(function (taggedUser) {
      // Remove the "@" symbol from the tagged user
      var username = taggedUser.slice(1);
      // Create a span element to highlight the tagged user
      var userSpan = document.createElement("span");
      userSpan.classList.add("tagged-user");
      userSpan.innerText = taggedUser;
      // Replace the tagged user text with the span element
      messageInput.value = messageInput.value.replace(taggedUser, userSpan.outerHTML);

      // Send a notification to the tagged user
      sendNotification(username);
    });
  }

  // Set the message text
  message.innerHTML = messageInput.value;

  // Append the message to the container
  messageContainer.appendChild(message);

  // Clear the input field
  messageInput.value = "";
}

// Function to send a notification to the tagged user
function sendNotification(username) {
  // Replace this with your own logic to send a notification
  console.log("Notification sent to @" + username);
}

// Add an event listener to the send button
var sendButton = document.getElementById("send-button");
sendButton.addEventListener("click", sendMessage);

// Add an event listener to the input field to handle sending messages on "Enter" key press
var messageInput = document.getElementById("message-input");
messageInput.addEventListener("keypress", function (event) {
  if (event.keyCode === 13) {
    sendMessage();
  }
});
